def solve(n : Int64, edges : Array(Array(Int64)), k : Int64) : Int64
  # Sort edges by weight
  edges.sort! { |a, b| a[2] <=> b[2] }

  # Union-Find data structure
  class UnionFind
    def initialize(size)
      @parent = Array.new(size) { |i| i }
      @rank = Array.new(size) { 0 }
    end

    def find(x)
      unless @parent[x] == x
        @parent[x] = find(@parent[x])
      end
      @parent[x]
    end

    def union(x, y)
      x_root = find(x)
      y_root = find(y)
      return if x_root == y_root

      if @rank[x_root] < @rank[y_root]
        @parent[x_root] = y_root
      else
        @parent[y_root] = x_root
        @rank[x_root] += 1 if @rank[x_root] == @rank[y_root]
      end
    end

    def get_parents
      @parent
    end
  end

  uf = UnionFind.new(n)
  components = Array.new(n) { 0 }
  max_weight = 0

  # Process edges in order of increasing weight
  edges.each do |u, v, w|
    uf.union(u, v)
    # Check if the number of components is greater than k
    # We need to find the maximum weight of the components
    # We can track the number of components by counting the number of unique roots
    roots = uf.get_parents.uniq
    if roots.size > k
      # The current edge's weight is the maximum weight of the components
      max_weight = w
    end
  end

  max_weight
end
